export default function InboxBadge() {
  const [unreadCount, setUnreadCount] = useState(0);

  return (
    <div>
      <button onClick={() => setUnreadCount(c => c + 1)}>Add Message</button>
      <button onClick={() => setUnreadCount(0)}>Clear</button>
      {unreadCount && <span className="badge">{unreadCount} unread</span>}
    </div>
  );
}

